+        }
+
+        uint32_t type_size;
+        log_file >> type_size;
+        uint64_t num_iterations;
+        log_file >> num_iterations;
+        uint32_t entry_size = type_size + FILE_POSITION_SIZE;
+
+        DataStream stream;
+        stream.resize(entry_size);
+
+        for (uint32_t i = 0; i < num_iterations; i++) {
