+            stream.ignore(type_size);
+            int64_t pos;
+            stream >> pos;
+
+            uint32_t re_checksum = crc32c::Crc32c(UCharCast(stream.data()), entry_size);
+            re_rolling_checksum = crc32c::Extend(re_rolling_checksum, UCharCast(stream.data()), entry_size);
+            uint32_t checksum;
+            log_file >> checksum;
+            if (re_checksum != checksum) {
