+            throw std::runtime_error("Could not create reindexing flag file");
+        }
+    } else {
+        std::error_code ec;
+        fs::remove(m_reindex_flag_file_path, ec);
+        if (ec && ec != std::errc::no_such_file_or_directory) {
+            throw std::runtime_error("Could not remove reindexing flag");
