+void BlockTreeStore::WritePruned(bool pruned) const
+{
+    LOCK(m_mutex);
+    if (pruned) {
+        if (auto file{AutoFile{fsbridge::fopen(m_prune_flag_file_path, "w")}}; file.IsNull() || file.fclose()) {
+            throw BlockTreeStoreError("Could not create prune flag file");
+        }
+    } else {
+        std::error_code ec;
+        fs::remove(m_prune_flag_file_path, ec);
+        if (ec && ec != std::errc::no_such_file_or_directory) {
+            throw BlockTreeStoreError("Could not remove prune flag");
+        }
+    }
+}
