+static uint8_t SizeFromValueType(const ValueType value_type)
+{
+    switch (value_type) {
+    case ValueType::LAST_BLOCK:
+        return LAST_BLOCK_TYPE_SIZE;
+    case ValueType::BLOCK_FILE_INFO:
+        return BLOCK_FILE_INFO_WRAPPER_SIZE;
+    case ValueType::DISK_BLOCK_INDEX:
+        return DISK_BLOCK_INDEX_WRAPPER_SIZE;
+    }
+    throw std::ios_base::failure("Invalid ValueType");
