+            throw BlockTreeStoreError("Could not create reindexing flag file");
+        }
+    } else {
+        std::error_code ec;
+        fs::remove(m_reindex_flag_file_path, ec);
+        if (ec && ec != std::errc::no_such_file_or_directory) {
+            throw BlockTreeStoreError("Could not remove reindexing flag");
+        }
+    }
+    DirectoryCommit(m_reindex_flag_file_path.parent_path());
+}
